mapper.select:
select id, bid_id, file_name, original_name, file_url, file_size, file_type, file_stage, parse_status, parse_report_id, create_time, update_time
from tdw_tender_file
where id = #{id}

select id, bid_id, file_name, original_name, file_url, file_size, file_type, file_stage, parse_status, parse_report_id, create_time, update_time
from tdw_tender_file
where bid_id = #{bidId}
  and file_stage = #{fileStage}
order by update_time desc, id desc
limit 1

select b.id, b.title, b.template_id, b.status, b.category, b.created_time, b.userid, b.deptid, b.unitid, b.note from tdw_bids b
and exists ( select 1 from tdw_tender_file f where f.bid_id = b.id ) and b.title like concat('%', #{title}, '%') and b.category = #{category} and b.status = #{status}
order by b.created_time desc, b.id desc

mapper.update:
update tdw_tender_file
file_name = #{fileName}, original_name = #{originalName}, file_url = #{fileUrl}, file_size = #{fileSize}, file_type = #{fileType}, file_stage = #{fileStage}, parse_status = #{parseStatus}, parse_report_id = #{parseReportId}, update_time = now(),
where id = #{id}
